+    const handle = await root.getFileHandle(`${CACHE_PREFIX}-${key}.sqlite3`);
+    const file = await handle.getFile();
+    const buffer = await file.arrayBuffer();
+    return new Uint8Array(buffer);
+  } catch {
+    return null;
+  }
