+async function readOpfsMetadata(key) {
+  const root = await getOpfsRoot();
+  if (!root) {
+    return null;
+  }
+  try {
+    const handle = await root.getFileHandle(`${CACHE_PREFIX}-${key}.meta.json`);
+    const file = await handle.getFile();
+    const text = await file.text();
