+async function loadBinary(path) {
+  const response = await fetch(path, { cache: "no-store" });
+  if (!response.ok) {
+    throw new Error(`Failed to fetch ${path} (${response.status})`);
+  }
+  return new Uint8Array(await response.arrayBuffer());
