+function formatChunkPath(pattern, index) {
+  return pattern.replace(/\{index(?::0?(\d+)d)?\}/, (_match, width) => {
+    const targetWidth = width ? Number(width) : 0;
+    return String(index).padStart(targetWidth, "0");
+  });
