+      if (this.filters.importance) {
+        const importanceFilter = this.filters.importance.toLowerCase();
+        filtered = filtered.filter(msg => (msg.importance || '').toLowerCase() === importanceFilter);
+      }
+
+      if (this.filters.hasThread) {
